"use client";

import * as React from "react";
import {
  Badge,
  Button,
  EmptyState,
  FileUploader,
  Progress,
  cn,
} from "@gunjo/ui";
import {
  IconFile,
  IconX,
  IconCircleCheck,
  IconAlertTriangle,
  IconCloudUpload,
  IconTrash,
} from "@tabler/icons-react";

type UploadStatus = "pending" | "uploading" | "complete" | "error";

interface TrackedFile {
  id: string;
  file: File;
  progress: number;
  status: UploadStatus;
  error?: string;
}

const MAX_SIZE = 10 * 1024 * 1024; // 10MB per file

function formatBytes(bytes: number): string {
  if (bytes === 0) return "0 B";
  const units = ["B", "KB", "MB", "GB"];
  const i = Math.floor(Math.log(bytes) / Math.log(1024));
  const value = bytes / Math.pow(1024, i);
  return `${value.toFixed(value >= 10 || i === 0 ? 0 : 1)} ${units[i]}`;
}

function prettyType(file: File): string {
  if (file.type) return file.type;
  const ext = file.name.includes(".")
    ? file.name.split(".").pop()?.toUpperCase()
    : undefined;
  return ext ? `${ext} ファイル` : "不明";
}

function statusBadge(status: UploadStatus) {
  switch (status) {
    case "complete":
      return (
        <Badge variant="secondary" className="gap-1">
          <IconCircleCheck className="h-3 w-3" />
          完了
        </Badge>
      );
    case "error":
      return (
        <Badge variant="destructive" className="gap-1">
          <IconAlertTriangle className="h-3 w-3" />
          失敗
        </Badge>
      );
    case "uploading":
      return <Badge variant="outline">アップロード中…</Badge>;
    default:
      return <Badge variant="outline">準備完了</Badge>;
  }
}

export default function UploadPage() {
  const [files, setFiles] = React.useState<TrackedFile[]>([]);

  // A single ticking interval advances every "uploading" file. This avoids
  // per-file timer bookkeeping and keeps all side effects out of the state
  // updater (which React 19 Strict Mode may invoke twice in dev).
  const anyUploading = files.some((f) => f.status === "uploading");
  React.useEffect(() => {
    if (!anyUploading) return;
    const tick = setInterval(() => {
      setFiles((prev) =>
        prev.map((f) => {
          if (f.status !== "uploading") return f;
          const next = Math.min(100, f.progress + 8 + Math.random() * 14);
          if (next >= 100) {
            const willError = f.file.size > 8 * 1024 * 1024;
            return {
              ...f,
              progress: 100,
              status: willError ? "error" : "complete",
              error: willError ? "サーバーがファイルを拒否しました" : undefined,
            };
          }
          return { ...f, progress: next };
        }),
      );
    }, 250);
    return () => clearInterval(tick);
  }, [anyUploading]);

  const addFiles = React.useCallback((incoming: File[]) => {
    if (incoming.length === 0) return;
    setFiles((prev) => {
      const next: TrackedFile[] = incoming.map((file) => {
        const tooLarge = file.size > MAX_SIZE;
        return {
          id: `${file.name}-${file.size}-${file.lastModified}-${Math.random()
            .toString(36)
            .slice(2, 8)}`,
          file,
          progress: 0,
          // Mark over-limit files as errored up front.
          status: tooLarge ? "error" : "pending",
          error: tooLarge ? "10MBの上限を超えています" : undefined,
        };
      });
      return [...prev, ...next];
    });
  }, []);

  const removeFile = React.useCallback((id: string) => {
    setFiles((prev) => prev.filter((f) => f.id !== id));
  }, []);

  const clearAll = React.useCallback(() => {
    setFiles([]);
  }, []);

  // Kick off all pending files; the ticking effect above drives their progress.
  const uploadAll = React.useCallback(() => {
    setFiles((prev) =>
      prev.map((f) =>
        f.status === "pending"
          ? { ...f, status: "uploading", progress: 0 }
          : f,
      ),
    );
  }, []);

  const totalSize = files.reduce((sum, f) => sum + f.file.size, 0);
  const pendingCount = files.filter((f) => f.status === "pending").length;
  const uploadingCount = files.filter((f) => f.status === "uploading").length;

  return (
    <main className="mx-auto w-full max-w-2xl px-6 py-12">
      <header className="mb-6 space-y-1">
        <h1 className="text-2xl font-semibold tracking-tight text-foreground">
          ファイルをアップロード
        </h1>
        <p className="text-sm text-muted-foreground">
          ドラッグ＆ドロップ、または選択してください。1ファイルあたり最大
          10&nbsp;MB。8&nbsp;MB を超えるファイルはサーバーエラーを再現します。
        </p>
      </header>

      {/*
        FileUploader is used purely as the dropzone / file picker. It manages
        its own internal file list, but that list is uncontrolled and renders
        no progress, so we hide it (see the scoped style below) and drive the
        real list + progress from our own state via onValueChange.
      */}
      <style>{`[data-slot="file-uploader"] > div:nth-child(2) { display: none; }`}</style>
      <FileUploader
        maxFiles={20}
        maxSize={MAX_SIZE}
        onValueChange={addFiles}
        className="max-w-none"
      />

      {/* Overall state bar */}
      <section className="mt-6">
        {files.length === 0 ? (
          <EmptyState
            icon={<IconCloudUpload className="h-6 w-6" />}
            title="ファイルが選択されていません"
            description="上のエリアにファイルをドロップするか、ドロップゾーンをクリックしてアップロードするファイルを選択してください。"
          />
        ) : (
          <>
            <div className="mb-3 flex flex-wrap items-center justify-between gap-3">
              <div className="flex items-center gap-2 text-sm">
                <Badge variant="secondary">{files.length} 件</Badge>
                <span className="text-muted-foreground">
                  合計 {formatBytes(totalSize)}
                </span>
              </div>
              <div className="flex items-center gap-2">
                <Button variant="ghost" size="sm" onClick={clearAll}>
                  <IconTrash className="h-4 w-4" />
                  すべてクリア
                </Button>
                <Button
                  variant="primary"
                  size="sm"
                  onClick={uploadAll}
                  disabled={pendingCount === 0}
                >
                  <IconCloudUpload className="h-4 w-4" />
                  {uploadingCount > 0
                    ? "アップロード中…"
                    : `すべてアップロード${pendingCount ? `（${pendingCount}件）` : ""}`}
                </Button>
              </div>
            </div>

            <ul className="grid gap-2">
              {files.map((f) => (
                <li
                  key={f.id}
                  className="rounded-lg border border-border bg-background p-3"
                >
                  <div className="flex items-start gap-3">
                    <div className="mt-0.5 flex h-9 w-9 shrink-0 items-center justify-center rounded-md bg-muted text-muted-foreground">
                      <IconFile className="h-4 w-4" />
                    </div>
                    <div className="min-w-0 flex-1">
                      <div className="flex items-center justify-between gap-2">
                        <span className="truncate text-sm font-medium text-foreground">
                          {f.file.name}
                        </span>
                        <div className="flex shrink-0 items-center gap-2">
                          {statusBadge(f.status)}
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-7 w-7"
                            aria-label={`${f.file.name} を削除`}
                            onClick={() => removeFile(f.id)}
                          >
                            <IconX className="h-4 w-4" />
                          </Button>
                        </div>
                      </div>
                      <div className="mt-0.5 flex items-center gap-2 text-xs text-muted-foreground">
                        <span>{formatBytes(f.file.size)}</span>
                        <span aria-hidden>•</span>
                        <span className="truncate">{prettyType(f.file)}</span>
                      </div>

                      {(f.status === "uploading" || f.status === "complete") && (
                        <div className="mt-2 flex items-center gap-2">
                          <Progress
                            value={f.progress}
                            className={cn(
                              "h-2 w-full",
                              f.status === "complete" && "opacity-70",
                            )}
                            aria-label={`${f.file.name} のアップロード進捗`}
                          />
                          <span className="w-9 shrink-0 text-right text-xs tabular-nums text-muted-foreground">
                            {Math.round(f.progress)}%
                          </span>
                        </div>
                      )}

                      {f.status === "error" && f.error && (
                        <p className="mt-2 text-xs font-medium text-destructive-strong">
                          {f.error}
                        </p>
                      )}
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          </>
        )}
      </section>
    </main>
  );
}
